/**
 * Generate Zep firewall config.
 *
 * Data source: https://help.getzep.com/api
 *
 * Zep is a long-term memory service for AI agents.
 * Uses "Api-Key" authorization scheme (not Bearer).
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://help.getzep.com/api";
// Zep API keys use "z_" prefix followed by ~32 alphanumeric characters.
const PLACEHOLDER_VALUE = "z_CoffeeSafeLocalCoffeeSafeLocalCo";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Zep API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:zep",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const zepFirewall = {",
    '  name: "zep",',
    '  description: "Zep",',
    "  placeholders: {",
    `    ZEP_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.getzep.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Api-Key ${{ secrets.ZEP_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Zep firewall config...");
  const ts = generateTypeScript();
  writeOutput("zep", ts, import.meta.dirname);
}
